VALUES
  ('judicial-d41b007d-moex-00084', 'judicial-d41b007d', 'judicial-d41b007d-moex-111-3d2b73b6', 'sub-judicial-d41b007d-07', NULL, 'single_choice', '中央警察大學研究所碩士班入學考試招生簡章，以有無色盲決定能否取得入學資格之規定，依司法院釋字 第626號解釋，下列敘述何者錯誤？', '["相關入學資格條件之設定，為大學自治事項，於合理及必要之範圍內，不生違反法律保留之問題", "受國民教育以外教育之權利雖受憲法第22條所保障，但不包括賦予人民請求給予入學許可之權利", "警大自治權之行使，應受其功能本質之限制，且為確保其達成國家賦予之政策功能，而應接受比一般大 學更多之國家監督", "鑑於色盲非屬人力所得控制之生理缺陷，警察大學作為培養國家警察專門人才之學術單位，自不得以此 作為差別待遇標準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:07+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "觀護人(選試少年事件處理法)"}'::jsonb, NULL),
  ('judicial-d41b007d-moex-00085', 'judicial-d41b007d', 'judicial-d41b007d-moex-111-3d2b73b6', 'sub-judicial-d41b007d-07', NULL, 'single_choice', '法律規定汽車駕駛人駕車強行闖越鐵路平交道，因而肇事者，處新臺幣1萬5千元以上9萬元以下罰鍰， 並吊銷其駕駛執照，終身不得考領駕駛執照，並應接受道路交通安全講習。關於上開規定，依司法院釋字 第780號解釋，下列敘述何者錯誤？', '["處以罰鍰係對汽車駕駛人財產權之限制", "終身不得考領駕駛執照，係限制汽車駕駛人之一般行為自由", "如駕駛人為職業駕駛人，則吊銷其駕駛執照將涉及人民選擇職業自由之客觀條件限制", "強制駕駛人參加道路交通安全講習，係對人民一般行為自由之限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:07+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "觀護人(選試少年事件處理法)"}'::jsonb, NULL),
  ('judicial-d41b007d-moex-00086', 'judicial-d41b007d', 'judicial-d41b007d-moex-111-3d2b73b6', 'sub-judicial-d41b007d-07', NULL, 'single_choice', '有關憲法第22條所稱「其他權利」，下列敘述何者正確？', '["「不妨礙社會秩序公共利益」應遵循社會多數意見作解釋", "本條之基本權利位階及效力較其他基本權劣後", "大法官依據本條而導出新聞自由之保障", "本條會隨著時代及社會的發展而進展"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:07+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "觀護人(選試少年事件處理法)"}'::jsonb, NULL),
  ('judicial-d41b007d-moex-00087', 'judicial-d41b007d', 'judicial-d41b007d-moex-111-3d2b73b6', 'sub-judicial-d41b007d-07', NULL, 'single_choice', '下列何者尚未經司法院大法官解釋明白承認屬憲法財產權之保障範圍？', '["攜帶外幣出入國境須報明登記，違反者應予沒入", "主管機關就其徵收之土地，應定期通知原所有權人土地之後續使用情形", "政府採購得標廠商在符合一定要件下，應於履約期間僱用一定比例之原住民員工", "人民依法請求國家賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:07+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "觀護人(選試少年事件處理法)"}'::jsonb, NULL),
  ('judicial-d41b007d-moex-00088', 'judicial-d41b007d', 'judicial-d41b007d-moex-111-3d2b73b6', 'sub-judicial-d41b007d-07', NULL, 'single_choice', '依憲法訴訟法規定，人民不得針對下列何者聲請判決？', '["最高法院之不利確定終局裁定適用之法律", "最高行政法院之不利確定終局判決", "監察院之彈劾案", "地方自治團體制定之自治條例"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:07+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "觀護人(選試少年事件處理法)"}'::jsonb, NULL),
  ('judicial-d41b007d-moex-00089', 'judicial-d41b007d', 'judicial-d41b007d-moex-111-3d2b73b6', 'sub-judicial-d41b007d-07', NULL, 'single_choice', '在我國憲法體制之下，下列何者得行使憲法上之行政權？', '["總統", "立法院國防委員會", "監察院", "懲戒法院"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:07+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "觀護人(選試少年事件處理法)"}'::jsonb, NULL),
  ('judicial-d41b007d-moex-00090', 'judicial-d41b007d', 'judicial-d41b007d-moex-111-3d2b73b6', 'sub-judicial-d41b007d-07', NULL, 'single_choice', '有關國會質詢權之敘述，下列何者錯誤？', '["司法、考試、監察三院院長，得不受邀備詢，乃係基於憲政慣例", "參謀總長得不受邀備詢，乃係基於國防事務乃屬總統權限", "檢察官得不受邀備詢，乃係基於其依法獨立行使職權、不受外部干涉", "公平交易委員會委員得不受邀備詢，乃係基於其依法獨立行使職權、不受外部干涉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:07+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "觀護人(選試少年事件處理法)"}'::jsonb, NULL),
  ('judicial-d41b007d-moex-00091', 'judicial-d41b007d', 'judicial-d41b007d-moex-111-3d2b73b6', 'sub-judicial-d41b007d-07', NULL, 'single_choice', '關於審計權之行使，下列敘述何者錯誤？', '["監察院設審計長，由總統提名，經立法院同意任命之", "審計長應於行政院提出決算後3個月內，依法完成其審核", "審計長完成決算審核後，應提出審核報告於立法院", "地方之審計權屬於地方立法並執行之事項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:07+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "觀護人(選試少年事件處理法)"}'::jsonb, NULL),
  ('judicial-d41b007d-moex-00092', 'judicial-d41b007d', 'judicial-d41b007d-moex-111-3d2b73b6', 'sub-judicial-d41b007d-07', NULL, 'single_choice', '有關公務員懲戒，下列敘述何者正確？', '["法官之懲戒，亦包括大法官", "公務員懲戒法之適用對象，包括文職及武職之公務員、公立學校教師", "公務員懲戒案件之審理，為一級一審制", "司法院大法官之懲戒，得經司法院大法官現有總額3分之2以上之出席及出席人數3分之2以上之決 議，由司法院移送懲戒法院審理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:07+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "觀護人(選試少年事件處理法)"}'::jsonb, NULL),
